import requests
import json

# Let's search RCSB PDB for "MDM2" or "Mdm2" to find structure of binders.
# We will use the RCSB PDB Search API.
url = "https://search.rcsb.org/rcsbsearch/v2/query"
query = {
    "query": {
        "type": "group",
        "logical_operator": "and",
        "nodes": [
            {
                "type": "terminal",
                "service": "text",
                "parameters": {
                    "attribute": "rcsb_polymer_entity_annotation.annotation",
                    "operator": "contains_phrase",
                    "value": "MDM2"
                }
            }
        ]
    },
    "return_type": "entry"
}

try:
    response = requests.post(url, json=query)
    if response.status_code == 200:
        results = response.json()
        print(f"Found {results.get('total_count', 0)} PDB entries containing MDM2 annotations.")
        # print first 10 entries
        entries = [item['identifier'] for item in results.get('result_set', [])[:20]]
        print("First 20 PDB entries:", entries)
    else:
        print(f"Failed to query RCSB: {response.status_code}")
except Exception as e:
    print(f"Error querying RCSB: {e}")

