import requests
import json

# Let's search RCSB PDB for complexes of Q00987 (MDM2) with antibodies or nanobodies.
# We can fetch macromolecules from the PDB search and look for "antibody", "monoclonal", "single-domain", "nanobody", "scFv", "Fab", etc.
# Or we can query PDB with a text search for both Q00987 and ("antibody" OR "nanobody" OR "scfv" OR "fab" OR "immunoglobulin" OR "binder")
