        print(f"Found {results.get('total_count', 0)} PDB antibody/nanobody complexes for MDM2.")
        entries = [item['identifier'] for item in results.get('result_set', [])]
        print("Complex PDB IDs:", entries)
    else:
        print(f"Failed to query RCSB: {response.status_code}")
except Exception as e:
    print(f"Error: {e}")

